*, *::before, *::after {
  box-sizing: border-box;
}

.card {
  width: 300px;
  padding: 16px;   /* stays 300px total — not 332px */
  border: 1px solid #ccc;
}

.badge {
  display: inline-block;
  padding: 4px 10px;   /* vertical padding works */
  width: 80px;         /* width works */
  border-radius: 12px;
}

/* gap trick: set font-size: 0 on parent to kill whitespace nodes */
.nav {
  font-size: 0;
}
.nav a {
  display: inline-block;
  font-size: 1rem;
}

/* (0,0,1) — element */
p { color: black; }

/* (0,1,0) — class */
.highlight { color: blue; }

/* (0,1,1) — class + element */
p.highlight { color: green; }   /* wins over .highlight alone */

/* (1,0,0) — ID beats all above */
#intro { color: red; }

/* @layer: base styles lose to unlayered rules regardless of specificity */
@layer base {
  p { color: black; }
}

body {
  font-family: Inter, sans-serif; /* inherited by all descendants */
  color: #111;
}

.reset-btn {
  font: inherit;     /* buttons don't inherit font by default — fix it */
  color: inherit;
  border: none;
  background: none;
}

/* Pseudo-class — state based */
.btn:hover { background: #0056b3; }
.btn:focus-visible { outline: 2px solid #0056b3; }

/* Pseudo-element — virtual node */
.tooltip::after {
  content: '';
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  border: 6px solid transparent;
  border-top-color: #333;
}

/* Grid: two-dimensional page shell */
.app {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 60px 1fr;
  grid-template-areas:
    'sidebar header'
    'sidebar main';
  height: 100vh;
}

/* Flex: one-dimensional header alignment */
.header {
  grid-area: header;
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 0 1.5rem;
}

/* Tooltip pattern */
.trigger {
  position: relative; /* establishes containing block */
}
.tooltip {
  position: absolute;
  top: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%);
}

/* Sticky table header */
th {
  position: sticky;
  top: 0;
  background: white; /* needed — sticky is transparent by default */
  z-index: 1;
}

@layer reset, base, components, utilities;

@layer reset {
  * { margin: 0; padding: 0; }
}

@layer base {
  body { font-family: Inter, sans-serif; }
}

@layer components {
  .btn { padding: 8px 16px; border-radius: 4px; }
}

@layer utilities {
  .mt-4 { margin-top: 1rem; } /* beats components regardless of specificity */
}

:root {
  --color-bg: #ffffff;
  --color-text: #111111;
  --color-primary: #0070f3;
}

.dark {
  --color-bg: #0a0a0a;
  --color-text: #ededed;
  --color-primary: #3b82f6;
}

body {
  background: var(--color-bg);
  color: var(--color-text);
}

/* Animate with @property */
@property --progress {
  syntax: '<number>';
  initial-value: 1;
  inherits: false;
}

/* Token scale — prevents z-index wars */
:root {
  --z-base: 0;
  --z-dropdown: 100;
  --z-sticky: 200;
  --z-overlay: 300;
  --z-modal: 400;
  --z-toast: 500;
}

/* Context trap — avoid this pattern */
.parent {
  transform: translateX(0); /* creates stacking context! */
  position: relative;
  z-index: 1;
}
.child {
  z-index: 9999; /* only beats siblings inside .parent, NOT global elements */
}

:root {
  font-size: 100%; /* respects browser default — usually 16px */
}

.heading { font-size: 2rem; }     /* 32px — always relative to root */
.subtext { font-size: 0.875rem; } /* 14px */
.card    { padding: 1.5rem; }     /* 24px — scales with zoom */

/* Mobile full-height — use dvh not vh */
.hero {
  height: 100dvh; /* accounts for collapsing browser chrome */
}

/* Transition: state change */
.btn {
  background: #0070f3;
  transition: background-color 150ms ease, transform 150ms ease;
}
.btn:hover {
  background: #0056b3;
  transform: translateY(-1px);
}

/* Animation: autonomous loop */
@keyframes spin {
  to { transform: rotate(360deg); }
}
.spinner {
  animation: spin 1s linear infinite;
}

/* Accessibility */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* Mobile-first base */
.grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

/* Tablet: 2 columns */
@media (min-width: 40em) {
  .grid { grid-template-columns: repeat(2, 1fr); }
}

/* Desktop: 3 columns */
@media (min-width: 64em) {
  .grid { grid-template-columns: repeat(3, 1fr); }
}

/* Intrinsic responsive — no media query needed */
.auto-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
}

/* BAD: triggers reflow every frame */
.modal-bad {
  transition: top 300ms ease;
  top: -100px; /* layout property */
}

/* GOOD: GPU composited — no reflow */
.modal-good {
  transition: transform 300ms ease, opacity 300ms ease;
  transform: translateY(-20px);
  opacity: 0;
}
.modal-good.visible {
  transform: translateY(0);
  opacity: 1;
}

/* Promote to own layer only when it will actually animate */
.chart-canvas {
  will-change: transform;
}

.gallery {
  display: grid;
  /* auto-fill: keeps empty tracks | auto-fit: collapses them */
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  grid-auto-rows: 220px; /* implicit rows are 220px */
  gap: 1rem;
}

/* Featured item spans 2 columns — works even in implicit grid */
.gallery__featured {
  grid-column: span 2;
  grid-row: span 2;
}

/* Isolated card widget */
.card {
  contain: content; /* shorthand for layout + paint */
}

/* Virtual rendering for long lists */
.feed-item {
  content-visibility: auto;
  /* Placeholder size while off-screen — prevents scrollbar jump */
  contain-intrinsic-size: 0 320px;
}

/* Strict containment for fixed-size widgets */
.avatar {
  width: 48px;
  height: 48px;
  contain: strict; /* size + layout + paint + style */
}

/* Physical — breaks in RTL */
.card-bad {
  margin-left: 1rem;
  padding-right: 1.5rem;
  border-left: 3px solid blue;
}

/* Logical — works in LTR and RTL automatically */
.card-good {
  margin-inline-start: 1rem;
  padding-inline-end: 1.5rem;
  border-inline-start: 3px solid blue;
}

/* Text alignment */
.label {
  text-align: start; /* left in LTR, right in RTL */
}

/* @property — register a typed custom property */
@property --gradient-angle {
  syntax: '<angle>';
  initial-value: 0deg;
  inherits: false;
}

/* Now it can be transitioned/animated */
.gradient-card {
  background: conic-gradient(from var(--gradient-angle), #0070f3, #7928ca, #0070f3);
  transition: --gradient-angle 1s ease;
}
.gradient-card:hover {
  --gradient-angle: 360deg; /* animates because type is registered */
}

